import{_ as t,o as s,c as e,a3 as i}from"./chunks/framework.CGpxwYOt.js";const h=JSON.parse('{"title":"2.5 玩家推进活动","description":"本节点为目录/结构标题，具体操作内容见其下级章节。 需要玩家通过各种游戏内活动来满足活动开启条件的，都称之为玩家推荐活动。 玩家活动如：击杀该地图怪物，完成该地图任务，击杀玩家等。 根据触发任务类型分为以下两种： ①荣誉类（鲸鱼、烛台） ②","frontmatter":{"title":"2.5 玩家推进活动","description":"本节点为目录/结构标题，具体操作内容见其下级章节。 需要玩家通过各种游戏内活动来满足活动开启条件的，都称之为玩家推荐活动。 玩家活动如：击杀该地图怪物，完成该地图任务，击杀玩家等。 根据触发任务类型分为以下两种： ①荣誉类（鲸鱼、烛台） ②","outline":"deep"},"headers":[],"relativePath":"pve/2-5.md","filePath":"pve/2-5.md","lastUpdated":1782387794000}'),u={name:"pve/2-5.md"};function l(g,a,p,r,o,d){return s(),e("div",null,[...a[0]||(a[0]=[i('<h1 id="_2-5-玩家推进活动" tabindex="-1">2.5 玩家推进活动 <a id="s204-0cb47e06"></a> <a class="header-anchor" href="#_2-5-玩家推进活动" aria-label="Permalink to &quot;2.5 玩家推进活动 &lt;a id=&quot;s204-0cb47e06&quot;&gt;&lt;/a&gt;&quot;">​</a></h1><p>本节点为目录/结构标题，具体操作内容见其下级章节。</p><h2 id="_2-5-1-什么是玩家推进活动" tabindex="-1">2.5.1 什么是玩家推进活动 <a id="s205-0082b85c"></a> <a class="header-anchor" href="#_2-5-1-什么是玩家推进活动" aria-label="Permalink to &quot;2.5.1 什么是玩家推进活动 &lt;a id=&quot;s205-0082b85c&quot;&gt;&lt;/a&gt;&quot;">​</a></h2><p>需要玩家通过各种游戏内活动来满足活动开启条件的，都称之为玩家推荐活动。</p><p>玩家活动如：击杀该地图怪物，完成该地图任务，击杀玩家等。</p><h2 id="_2-5-2-玩家推进活动的种类" tabindex="-1">2.5.2 玩家推进活动的种类 <a id="s206-1caf436a"></a> <a class="header-anchor" href="#_2-5-2-玩家推进活动的种类" aria-label="Permalink to &quot;2.5.2 玩家推进活动的种类 &lt;a id=&quot;s206-1caf436a&quot;&gt;&lt;/a&gt;&quot;">​</a></h2><p>根据触发任务类型分为以下两种：</p><p>①荣誉类（鲸鱼、烛台）</p><p>②债券类（十字星平原与伊尼斯泰尔的战争跑图）</p><p>③开启BOSS 挑战类</p><h2 id="_2-5-3-玩家推进活动的参与" tabindex="-1">2.5.3 玩家推进活动的参与 <a id="s207-d70a133b"></a> <a class="header-anchor" href="#_2-5-3-玩家推进活动的参与" aria-label="Permalink to &quot;2.5.3 玩家推进活动的参与 &lt;a id=&quot;s207-d70a133b&quot;&gt;&lt;/a&gt;&quot;">​</a></h2><p>当鲸鱼烛台达到5 阶段后，或者有人开始组织推这些地图的战争阶段后就可以加入他们的团队。</p><p>注意：在有国人团队时，请不要加入敌对老外团队，以免被误伤。</p><h2 id="_2-5-4-玩家推进活动的收益" tabindex="-1">2.5.4 玩家推进活动的收益 <a id="s208-15c3d683"></a> <a class="header-anchor" href="#_2-5-4-玩家推进活动的收益" aria-label="Permalink to &quot;2.5.4 玩家推进活动的收益 &lt;a id=&quot;s208-15c3d683&quot;&gt;&lt;/a&gt;&quot;">​</a></h2><p>所有类型的推荐活动都可以获得荣誉。</p><p>在玩家有接取公会每日任务的情况下，鲸鱼可以在打完扎卡鲁后获得2 个豆奶，</p><p>烛台可以获得古代修复卷轴碎片X3。</p><p>跑图任务在达到100 活动分数，并且和平到来时仍在对应地图的话。可以通过出现的蓝颜商会的NPC 来接取债券任务，任务接取就可以提交。可以获得10 个德翡纳之星和3 个债券。</p><h2 id="_2-5-5-鲸鱼-wh-与烛台-ag" tabindex="-1">2.5.5 鲸鱼（WH）与烛台（AG） <a id="s209-b3c517bf"></a> <a class="header-anchor" href="#_2-5-5-鲸鱼-wh-与烛台-ag" aria-label="Permalink to &quot;2.5.5 鲸鱼（WH）与烛台（AG） &lt;a id=&quot;s209-b3c517bf&quot;&gt;&lt;/a&gt;&quot;">​</a></h2><p>鲸鱼和烛台在开始战争5 分钟后才会出怪，在打完BOSS 后，会刷新卖对应道具的走私鲁鲁。烛台是卖毒囊，鲸鱼是卖甲胄。</p><p>鲸鱼在神之盾野营地接任务：</p><p>甲胄鲁鲁如下：</p><p>烛台在神之盾补给营地接任务：</p><p>毒囊鲁鲁如下：</p><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_2359.jpeg" alt="图示：2.5.5 鲸鱼（WH）与烛台（AG）" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_2360.jpeg" alt="图示：2.5.5 鲸鱼（WH）与烛台（AG）" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_2366.jpeg" alt="图示：2.5.5 鲸鱼（WH）与烛台（AG）" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_2367.jpeg" alt="图示：2.5.5 鲸鱼（WH）与烛台（AG）" loading="lazy"></figure><h2 id="_2-5-6-十字星平原-cr-与伊尼斯泰尔-yny-的战争" tabindex="-1">2.5.6 十字星平原(CR)与伊尼斯泰尔(YNY)的战争 <a id="s210-b8312460"></a> <a class="header-anchor" href="#_2-5-6-十字星平原-cr-与伊尼斯泰尔-yny-的战争" aria-label="Permalink to &quot;2.5.6 十字星平原(CR)与伊尼斯泰尔(YNY)的战争 &lt;a id=&quot;s210-b8312460&quot;&gt;&lt;/a&gt;&quot;">​</a></h2><p>十字星平原和伊尼斯泰尔在纷争结束后会在该地图住民会馆旁边刷新跑图任务</p><p>NPC，如下：</p><p>红框为跑图开始时出现并接取任务的NPC，蓝框为跑图结束和平后出现的接取债券任务的NPC。</p><p>跑图任务如下：</p><p>如果一次没做完，可以放弃上图任务，下次接任务可以保留分数进度一样可以拿到和平的债券任务。</p><p>分数任务如下：</p><p>跑图结束和平时还在跑图地图可以从NPC 接取债券任务，如下：</p><p>伊尼斯泰尔跑图参考十字星部分，NPC 都是同一个组织的，位置在伊尼斯泰尔的住民。</p><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_2373.jpeg" alt="图示：2.5.6 十字星平原(CR)与伊尼斯泰尔(YNY)的战争" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_2374.jpeg" alt="图示：2.5.6 十字星平原(CR)与伊尼斯泰尔(YNY)的战争" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_2380.jpeg" alt="图示：2.5.6 十字星平原(CR)与伊尼斯泰尔(YNY)的战争" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_2381.jpeg" alt="图示：2.5.6 十字星平原(CR)与伊尼斯泰尔(YNY)的战争" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_2386.jpeg" alt="图示：2.5.6 十字星平原(CR)与伊尼斯泰尔(YNY)的战争" loading="lazy"></figure>',42)])])}const f=t(u,[["render",l]]);export{h as __pageData,f as default};
